mapper.select:
/*mapper.user.ReportMapper.findReportCount */ SELECT count(*) AS count FROM reports WHERE 1=1
AND TARGET_CODE = #{targetCode}
AND created_at between STR_TO_DATE(CONCAT(#{today},' 00:00:00'), '%Y-%m-%d %H:%i:%s') and STR_TO_DATE(CONCAT(#{today},' 23:59:59'), '%Y-%m-%d %H:%i:%s')

/*mapper.user.ReportMapper.findReportList */ SELECT r.REPORT_ID AS reportId , r.TARGET_CODE AS targetCode , r.TARGET_ID AS targetId , r.REPORTER_EMAIL AS reporterEmail , r.REASON_CODE AS reasonCode , r.DETAIL AS detail , r.REPORT_STATUS_CODE AS reportStatusCode , r.PROCESSED_BY AS processedBy , r.CREATED_AT AS createdAt , r.PROCESSED_AT AS processedAt
, CASE WHEN target_code = '01' THEN (SELECT u.NICKNAME FROM posts p JOIN users u ON p.USER_EMAIL = u.EMAIL WHERE p.post_id = r.TARGET_ID ) ELSE (SELECT u.NICKNAME FROM comments c JOIN users u ON c.USER_EMAIL = u.EMAIL WHERE c.comment_id = r.TARGET_ID ) END AS targetNickname , (SELECT NICKNAME FROM users WHERE EMAIL = r.REPORTER_EMAIL) AS reporterNickname , CASE WHEN target_code = '01' THEN (SELECT title FROM posts WHERE post_id = r.TARGET_ID) ELSE (SELECT content FROM comments WHERE comment_id = r.TARGET_ID) END AS content
FROM reports r WHERE 1=1
AND r.REPORT_ID < #{lastId}
AND r.TARGET_CODE = #{targetCode}
ORDER BY r.REPORT_ID DESC LIMIT #{size}
OFFSET #{offset}
